create table ticketnexus.tickets_tbl (
    id             number generated by default as identity not null enable,
    ticket_number  varchar2(50 char) not null enable,
    ticket_type_id number not null enable,
    title          varchar2(255 char) not null enable,
    description    clob,
    state_id       number not null enable,
    priority_id    number not null enable,
    impact_id      number not null enable,
    urgency_id     number not null enable,
    responsible_id number,
    due_date       timestamp(6),
    created_on     timestamp(6) default on null current_timestamp not null enable,
    created_by     varchar2(255 char) default on null coalesce(
        sys_context('APEX$SESSION', 'APP_USER'),
        user
    ) not null enable,
    updated_on     timestamp(6),
    updated_by     varchar2(255 char)
);

alter table ticketnexus.tickets_tbl
    add constraint tickets_pk primary key ( id )
        using index enable;

alter table ticketnexus.tickets_tbl add constraint tickets_uk1 unique ( ticket_number )
    using index enable;

